{
    if (dist < 5)
    {
        return dist - 1;
    }
    else
    {
        int l = (31 ^ __builtin_clz(dist - 1)); /* log2(dist - 1) */
        int r = ((dist - 1) >> (l - 1)) & 1;
        return l * 2 + r;
    }
}

static size_t AbsDiff(size_t x, size_t y)
{
    if (x > y)
        return x - y;
    else
        return y - x;
}

